public class AmortizedDemo {
    public static void main(String[] args) {
        System.out.println("=== ArrayList.add() Amortized Analysis ===");
        System.out.printf("%-8s %-10s %-15s %-15s %-15s%n",
            "Op #", "Capacity", "This op cost", "Total cost", "Amortized/op");
        System.out.println("-".repeat(65));

        int capacity = 1, size = 0, totalCost = 0;
        for (int i = 1; i <= 32; i++) {
            int thisCost;
            if (size == capacity) {
                // RESIZE: copy all existing elements
                thisCost = size + 1; // copy 'size' elements + 1 for new add
                capacity *= 2;
            } else {
                thisCost = 1; // just add
            }
            size++;
            totalCost += thisCost;
            double amortized = (double) totalCost / size;

            if (thisCost > 1 || i <= 5 || i == 16 || i == 32) {
                System.out.printf("%-8d %-10d %-15d %-15d %-15.2f%s%n",
                    i, capacity, thisCost, totalCost, amortized,
                    thisCost > 1 ? " ← RESIZE" : "");
            }
        }
        System.out.println();
        System.out.println("Key insight:");
        System.out.println("  Resizes happen at ops: 1,2,4,8,16,32... (doublings)");
        System.out.println("  Total resize cost = 1+2+4+8+16+... = 2n − 1 < 2n");
        System.out.println("  Amortized cost per add = 2n/n = 2 = O(1)");
        System.out.println("  This is why ArrayList.add() is 'amortized O(1)'");
    }
}

