import java.util.*;
public class QuicksortWorstCase {
    static long comparisons = 0;

    static void quicksort(int[] arr, int lo, int hi) {
        if (lo >= hi) return;
        int p = partition(arr, lo, hi);
        quicksort(arr, lo, p - 1);
        quicksort(arr, p + 1, hi);
    }

    static int partition(int[] arr, int lo, int hi) {
        int pivot = arr[hi]; // NAIVE: always last element
        int i = lo - 1;
        for (int j = lo; j < hi; j++) {
            comparisons++;
            if (arr[j] <= pivot) {
                i++;
                int tmp = arr[i]; arr[i] = arr[j]; arr[j] = tmp;
            }
        }
        int tmp = arr[i+1]; arr[i+1] = arr[hi]; arr[hi] = tmp;
        return i + 1;
    }

    public static void main(String[] args) {
        int n = 1000;
        double nLogN = n * Math.log(n) / Math.log(2);
        double nSquaredHalf = (double) n * n / 2;

        // Random array:
        int[] random = new int[n];
        Random rand = new Random(42);
        for (int i = 0; i < n; i++) random[i] = rand.nextInt(10000);
        comparisons = 0;
        quicksort(random, 0, n - 1);
        long randomComps = comparisons;

        // Sorted array (worst case for naive pivot):
        int[] sorted = new int[n];
        for (int i = 0; i < n; i++) sorted[i] = i;
        comparisons = 0;
        quicksort(sorted, 0, n - 1);
        long sortedComps = comparisons;

        System.out.println("n = " + n);
        System.out.printf("Theoretical O(n log n): %.0f comparisons%n", nLogN);
        System.out.printf("Theoretical O(n²/2):    %.0f comparisons%n", nSquaredHalf);
        System.out.println();
        System.out.println("Random input:  " + randomComps + " comparisons (≈ O(n log n))");
        System.out.println("Sorted input:  " + sortedComps + " comparisons (≈ O(n²))");
        System.out.printf("Slowdown: %.1fx more comparisons on sorted input%n",
            (double) sortedComps / randomComps);
        System.out.println();
        System.out.println("This is the Flipkart Big Billion Days bug:");
        System.out.println("  Sorted product IDs → naive pivot → O(n²) → timeout!");
    }
}

