import java.util.*;
public class RandomPivotQuicksort {
    static long comps = 0;
    static Random rand = new Random(42);

    static int partitionWithPivot(int[] arr, int lo, int hi, int pivotIdx) {
        // Move pivot to end first
        int tmp = arr[pivotIdx]; arr[pivotIdx] = arr[hi]; arr[hi] = tmp;
        int pivot = arr[hi], i = lo - 1;
        for (int j = lo; j < hi; j++) {
            comps++;
            if (arr[j] <= pivot) { i++; tmp=arr[i]; arr[i]=arr[j]; arr[j]=tmp; }
        }
        tmp=arr[i+1]; arr[i+1]=arr[hi]; arr[hi]=tmp;
        return i + 1;
    }

    static void quicksortNaive(int[] arr, int lo, int hi) {
        if (lo >= hi) return;
        int p = partitionWithPivot(arr, lo, hi, hi); // always last
        quicksortNaive(arr, lo, p-1);
        quicksortNaive(arr, p+1, hi);
    }

    static void quicksortRandom(int[] arr, int lo, int hi) {
        if (lo >= hi) return;
        int pivotIdx = lo + rand.nextInt(hi - lo + 1); // RANDOM pivot
        int p = partitionWithPivot(arr, lo, hi, pivotIdx);
        quicksortRandom(arr, lo, p-1);
        quicksortRandom(arr, p+1, hi);
    }

    public static void main(String[] args) {
        int n = 1000;
        int[] sorted = new int[n];
        for (int i = 0; i < n; i++) sorted[i] = i;

        comps = 0;
        quicksortNaive(sorted.clone(), 0, n-1);
        long naiveComps = comps;

        comps = 0;
        quicksortRandom(sorted.clone(), 0, n-1);
        long randomComps = comps;

        System.out.println("Sorted input, n=" + n);
        System.out.println("Naive pivot (last): " + naiveComps + " comparisons ← O(n²)");
        System.out.println("Random pivot:       " + randomComps + " comparisons ← O(n log n) expected");
        System.out.printf("Speedup: %.1fx fewer comparisons with random pivot%n",
            (double)naiveComps/randomComps);
        System.out.println();
        System.out.println("Both produce correctly sorted output.");
        System.out.println("Random pivot: O(n log n) EXPECTED — worst case still possible");
        System.out.println("but astronomically unlikely (requires adversarial input).");
    }
}

