import java.util.*;
public class HashMapCases {
    static class BadKey {
        int val;
        BadKey(int v) { val = v; }
        @Override public int hashCode() { return 0; } // all to bucket 0
        @Override public boolean equals(Object o) {
            return o instanceof BadKey && ((BadKey)o).val == val;
        }
    }

    public static void main(String[] args) {
        int n = 10_000;

        // Good HashMap: good hash function → O(1) average
        Map<Integer, Integer> goodMap = new HashMap<>();
        for (int i = 0; i < n; i++) goodMap.put(i, i);

        long s = System.currentTimeMillis();
        for (int i = 0; i < n; i++) goodMap.get(n - 1 - i);
        long goodTime = System.currentTimeMillis() - s;

        // Bad HashMap: all keys hash to 0 → O(n) per lookup
        Map<BadKey, Integer> badMap = new HashMap<>();
        for (int i = 0; i < n; i++) badMap.put(new BadKey(i), i);

        s = System.currentTimeMillis();
        for (int i = 0; i < n; i++) badMap.get(new BadKey(n - 1 - i));
        long badTime = System.currentTimeMillis() - s;

        System.out.println("n = " + n + " lookups");
        System.out.println("Good HashMap (O(1) avg): " + goodTime + "ms");
        System.out.println("Bad HashMap (O(n) worst): " + badTime + "ms");
        System.out.println();
        System.out.println("HashMap complexity summary:");
        System.out.println("  Best:    O(1) — key in own bucket, no collision");
        System.out.println("  Average: O(1) — good hash function, few collisions");
        System.out.println("  Worst:   O(n) — all keys same bucket (bad hashCode)");
        System.out.println();
        System.out.println("Java 8+ safeguard: bucket converts to TreeMap at 8+ entries");
        System.out.println("  → Practical worst case becomes O(log n) not O(n)");
    }
}

