import java.util.*;
public class BinarySearchCases {
    static int steps = 0;

    static int binarySearch(int[] arr, int target) {
        int lo = 0, hi = arr.length - 1;
        while (lo <= hi) {
            steps++;
            int mid = lo + (hi - lo) / 2;
            if (arr[mid] == target) return mid;
            if (arr[mid] < target) lo = mid + 1;
            else hi = mid - 1;
        }
        return -1;
    }

    public static void main(String[] args) {
        int n = 1024;
        int[] arr = new int[n];
        for (int i = 0; i < n; i++) arr[i] = i * 2; // even numbers: 0,2,4,...,2046

        int logN = (int)(Math.log(n) / Math.log(2)); // = 10 for n=1024

        System.out.println("n = " + n + ", log₂(n) = " + logN);
        System.out.println();

        // Best case: target IS the midpoint (index 511, value 1022)
        int bestTarget = arr[n / 2]; // exactly at first midpoint check
        steps = 0;
        binarySearch(arr, bestTarget);
        System.out.println("Best case:    target=" + bestTarget + " (at midpoint)");
        System.out.println("  Steps: " + steps + " → O(1)");
        System.out.println();

        // Average case: random target in array
        steps = 0;
        int totalSteps = 0;
        Random rand = new Random(42);
        for (int trial = 0; trial < 100; trial++) {
            steps = 0;
            int target = arr[rand.nextInt(n)];
            binarySearch(arr, target);
            totalSteps += steps;
        }
        System.out.println("Average case: 100 random targets");
        System.out.println("  Avg steps: " + (totalSteps/100.0) + " → O(log n ≈ " + logN + ")");
        System.out.println();

        // Worst case: target not present (must exhaust search)
        steps = 0;
        binarySearch(arr, 2047); // largest possible odd number (not in array of evens)
        System.out.println("Worst case:   target=2047 (not present)");
        System.out.println("  Steps: " + steps + " → O(log n = " + logN + ")");
        System.out.println();

        System.out.println("Key insight: best AND worst case both ≤ O(log n)");
        System.out.println("Binary search is remarkably consistent — never degrades!");
    }
}

