import java.util.*;
public class AmortizedStack {
    static Deque<Integer> stack = new ArrayDeque<>();
    static long totalCost = 0, opCount = 0;

    static void push(int x) {
        stack.push(x);
        totalCost += 1; // O(1) per push
        opCount++;
    }

    static void popAll() {
        int k = stack.size();
        stack.clear();
        totalCost += k; // O(k) — remove all k elements
        opCount++;
        System.out.println("  popAll() removed " + k + " elements, cost=" + k);
    }

    static void printAmortized() {
        System.out.printf("  Total cost so far: %d over %d ops → amortized %.2f per op%n",
            totalCost, opCount, (double)totalCost/opCount);
    }

    public static void main(String[] args) {
        System.out.println("=== Amortized Stack Analysis ===");
        System.out.println();

        // Phase 1: 10 pushes
        System.out.println("Phase 1: 10 pushes (each cost=1)");
        for (int i = 1; i <= 10; i++) push(i);
        printAmortized();
        System.out.println();

        // popAll: cost = current size
        System.out.println("Phase 2: popAll()");
        popAll();
        printAmortized();
        System.out.println();

        // Phase 3: 10 more pushes
        System.out.println("Phase 3: 10 more pushes");
        for (int i = 11; i <= 20; i++) push(i);
        printAmortized();
        System.out.println();

        System.out.println("=== Amortized Proof ===");
        System.out.println("Key insight: each element can only be popped ONCE after being pushed.");
        System.out.println("Total pops across ALL popAll() calls ≤ total pushes = n");
        System.out.println("Total cost = n pushes + ≤n pops = O(n)");
        System.out.println("Amortized per operation = O(n) / n = O(1)");
        System.out.println();
        System.out.printf("Our demonstration: %d total ops, %d total cost, %.2f amortized%n",
            opCount, totalCost, (double)totalCost/opCount);
    }
}

