import java.util.*;
public class InsertionSortCases {
    static long comparisons = 0;

    static int[] insertionSort(int[] arr) {
        int[] a = arr.clone();
        for (int i = 1; i < a.length; i++) {
            int key = a[i];
            int j = i - 1;
            while (j >= 0 && a[j] > key) {
                comparisons++;
                a[j + 1] = a[j];
                j--;
            }
            comparisons++; // the failed comparison that stops the while
            a[j + 1] = key;
        }
        return a;
    }

    public static void main(String[] args) {
        int n = 1000;
        double nSq = (double) n * n;
        double nVal = n;

        // Sorted input (best case):
        int[] sorted = new int[n];
        for (int i = 0; i < n; i++) sorted[i] = i;
        comparisons = 0;
        insertionSort(sorted);
        long sortedComps = comparisons;

        // Reverse sorted (worst case — maximum swaps):
        int[] reversed = new int[n];
        for (int i = 0; i < n; i++) reversed[i] = n - i;
        comparisons = 0;
        insertionSort(reversed);
        long reversedComps = comparisons;

        // Random (average case):
        int[] random = new int[n];
        Random rand = new Random(42);
        for (int i = 0; i < n; i++) random[i] = rand.nextInt(10000);
        comparisons = 0;
        insertionSort(random);
        long randomComps = comparisons;

        System.out.println("Insertion Sort, n=" + n);
        System.out.printf("Sorted input  (best):    %,d comparisons ≈ O(n=%d)%n", sortedComps, n);
        System.out.printf("Reversed input (worst):  %,d comparisons ≈ O(n²=%d)%n", reversedComps, (int)nSq/2);
        System.out.printf("Random input  (average): %,d comparisons ≈ O(n²/4)%n", randomComps);
        System.out.println();
        System.out.println("Why TimSort uses insertion sort for small subarrays (n < 64):");
        System.out.println("  - Real-world data is often NEARLY sorted");
        System.out.println("  - Insertion sort: O(n) on nearly-sorted ← key advantage");
        System.out.println("  - Low constant factor: minimal overhead for small n");
        System.out.println("  - Better cache performance than merge sort for small arrays");
        System.out.println("  - TimSort = merge sort (large n) + insertion sort (small n)");
        System.out.println("    → O(n) for already-sorted, O(n log n) otherwise");
    }
}

