public class UnionFind {
    int[] parent, rank;

    UnionFind(int n) {
        parent = new int[n];
        rank = new int[n];
        for (int i = 0; i < n; i++) parent[i] = i; // each is its own parent
    }

    // Path compression: make every node point directly to root
    int find(int x) {
        if (parent[x] != x)
            parent[x] = find(parent[x]); // compress path
        return parent[x];
    }

    // Union by rank: attach smaller tree under larger
    void union(int x, int y) {
        int rx = find(x), ry = find(y);
        if (rx == ry) return;
        if (rank[rx] < rank[ry]) { int tmp=rx; rx=ry; ry=tmp; }
        parent[ry] = rx;
        if (rank[rx] == rank[ry]) rank[rx]++;
    }

    boolean connected(int x, int y) { return find(x) == find(y); }

    public static void main(String[] args) {
        int n = 1_000_000;
        int ops = 10_000_000;
        UnionFind uf = new UnionFind(n);
        java.util.Random rand = new java.util.Random(42);

        long start = System.currentTimeMillis();
        for (int i = 0; i < ops; i++) {
            int a = rand.nextInt(n), b = rand.nextInt(n);
            if (i % 2 == 0) uf.union(a, b);
            else uf.connected(a, b);
        }
        long time = System.currentTimeMillis() - start;

        System.out.println("Union-Find with path compression + union by rank:");
        System.out.println("  n = " + n + " elements");
        System.out.println("  " + ops + " operations in " + time + "ms");
        System.out.printf("  Average per operation: %.4fms%n", (double)time/ops);
        System.out.println();
        System.out.println("Amortized complexity:");
        System.out.println("  O(α(n)) per operation — α is inverse Ackermann function");
        System.out.println("  α(10^80) ≈ 5 — effectively constant for any real input");
        System.out.println("  This is the definition of 'practically O(1) amortized'");
        System.out.println();
        System.out.println("Used in: Kruskal's MST, Cycle detection, Social network connectivity");
    }
}

