    static void printInterviewAnswers() {
        System.out.println("=== COMPLETE INTERVIEW ANSWERS ===");
        System.out.println();

        System.out.println("1. QUICKSORT:");
        System.out.println("   'Quicksort has O(n log n) average time and O(log n) space.");
        System.out.println("   The worst case is O(n²) — triggered when the pivot is always");
        System.out.println("   the smallest or largest element, e.g., sorted input with last-element");
        System.out.println("   pivot. We mitigate this with random pivot selection, making worst case");
        System.out.println("   astronomically unlikely. Best case is also O(n log n) when pivots");
        System.out.println("   always split the array perfectly in half.'");
        System.out.println();

        System.out.println("2. BUBBLE SORT:");
        System.out.println("   'Bubble sort is O(n²) time and O(1) space. With the early-exit");
        System.out.println("   optimization (stop if no swaps in a pass), best case is O(n) —");
        System.out.println("   triggered on already-sorted input. Stable sort: equal elements");
        System.out.println("   maintain relative order. In practice, not used for n > 1000");
        System.out.println("   due to O(n²) average/worst case.'");
        System.out.println();

        System.out.println("3. HASH TABLE (HashMap):");
        System.out.println("   'HashMap.get() and put() are O(1) average case, assuming a good");
        System.out.println("   hash function. Worst case is O(n) — when all keys hash to the same");
        System.out.println("   bucket forming a linked list. Java 8+ mitigates this: buckets");
        System.out.println("   with 8+ entries convert to Red-Black Trees, giving O(log n) worst case.");
        System.out.println("   Space: O(n) for n entries. Load factor 0.75: resize at 75% capacity.");
        System.out.println("   HashMap is NOT ordered — use TreeMap (O(log n)) for sorted keys.'");
    }

    static void benchmark() {
        System.out.println("=== BENCHMARK VERIFICATION ===");
        int n = 1000;

        // Verify quicksort worst case:
        int[] sorted = new int[n]; for (int i=0;i<n;i++) sorted[i]=i;
        long s = System.currentTimeMillis();
        Arrays.sort(sorted); // Java's sort avoids O(n²) — demonstrate manually
        System.out.println("Arrays.sort (dual-pivot, safeguarded): " + (System.currentTimeMillis()-s) + "ms on sorted input");

        // Verify HashMap O(1) average:
        Map<Integer,Integer> map = new HashMap<>();
