import java.util.*;
public class MedianOfThreeSort {
    static long comps;

    static int partitionAt(int[] arr, int lo, int hi, int pivotIdx) {
        int tmp = arr[pivotIdx]; arr[pivotIdx] = arr[hi]; arr[hi] = tmp;
        int pivot = arr[hi], i = lo - 1;
        for (int j = lo; j < hi; j++) {
            comps++;
            if (arr[j] <= pivot) { i++; tmp=arr[i]; arr[i]=arr[j]; arr[j]=tmp; }
        }
        tmp=arr[i+1]; arr[i+1]=arr[hi]; arr[hi]=tmp;
        return i + 1;
    }

    static void naiveQuicksort(int[] arr, int lo, int hi) {
        if (lo >= hi) return;
        int p = partitionAt(arr, lo, hi, hi); // last element
        naiveQuicksort(arr, lo, p-1);
        naiveQuicksort(arr, p+1, hi);
    }

    static int medianOf3(int[] arr, int lo, int hi) {
        int mid = lo + (hi - lo) / 2;
        // Sort lo, mid, hi by value and return index of median:
        if (arr[lo] > arr[mid]) { int t=arr[lo]; arr[lo]=arr[mid]; arr[mid]=t; }
        if (arr[lo] > arr[hi]) { int t=arr[lo]; arr[lo]=arr[hi]; arr[hi]=t; }
        if (arr[mid] > arr[hi]) { int t=arr[mid]; arr[mid]=arr[hi]; arr[hi]=t; }
        return mid; // arr[mid] is now the median of three
    }

    static void medianOfThreeSort(int[] arr, int lo, int hi) {
        if (lo >= hi) return;
        int pivotIdx = medianOf3(arr, lo, hi);
        int p = partitionAt(arr, lo, hi, pivotIdx);
        medianOfThreeSort(arr, lo, p-1);
        medianOfThreeSort(arr, p+1, hi);
    }

    public static void main(String[] args) {
        int n = 1000;

        // Test on sorted input:
        int[] sorted = new int[n];
        for (int i = 0; i < n; i++) sorted[i] = i;

        comps = 0; naiveQuicksort(sorted.clone(), 0, n-1);
        long naiveComps = comps;

        comps = 0; medianOfThreeSort(sorted.clone(), 0, n-1);
        long medianComps = comps;

        System.out.println("Sorted input, n=" + n + ":");
        System.out.printf("  Naive (last pivot):     %,d comparisons ← O(n²)%n", naiveComps);
        System.out.printf("  Median-of-three:        %,d comparisons ← O(n log n)%n", medianComps);
        System.out.printf("  Improvement: %.1fx fewer comparisons%n", (double)naiveComps/medianComps);
        System.out.println();

        // Verify correct output:
        int[] arr1 = sorted.clone(); naiveQuicksort(arr1, 0, n-1);
        int[] arr2 = sorted.clone(); medianOfThreeSort(arr2, 0, n-1);
        boolean correct = Arrays.equals(arr1, arr2);
        System.out.println("Both produce same sorted output: " + correct);
        System.out.println();
        System.out.println("Median-of-three insight:");
        System.out.println("  For sorted input: median(first, mid, last) picks the TRUE median");
        System.out.println("  → pivot splits array in half → O(n log n) not O(n²)");
        System.out.println("  For random input: similar to random pivot, O(n log n) expected");
    }
}

