import java.util.*;
public class ComplexityAdvisor {
    record Complexity(String algorithm, String best, String worst, String average,
                      String space, boolean stable, String worstTrigger, String mitigation) {}

    static Map<String, Complexity> db = new HashMap<>();
    static {
        db.put("quicksort",    new Complexity("Quicksort","O(n log n)","O(n²)","O(n log n)","O(log n)",false,"Sorted input + last-element pivot","Random pivot or median-of-three"));
        db.put("mergesort",    new Complexity("Merge Sort","O(n log n)","O(n log n)","O(n log n)","O(n)",true,"None — always O(n log n)","No mitigation needed"));
        db.put("bubblesort",   new Complexity("Bubble Sort","O(n)","O(n²)","O(n²)","O(1)",true,"Reverse-sorted input","Early exit: stop if no swaps in a pass"));
        db.put("binarysearch", new Complexity("Binary Search","O(1)","O(log n)","O(log n)","O(1)",false,"Target not present","No mitigation needed — O(log n) is already excellent"));
        db.put("hashmap",      new Complexity("HashMap","O(1)","O(n)","O(1)","O(n)",false,"All keys hash to same bucket","Good hashCode(); Java 8+ trees at 8+ entries → O(log n)"));
        db.put("linearsearch", new Complexity("Linear Search","O(1)","O(n)","O(n)","O(1)",false,"Target at last position or absent","Use sorted array + binary search instead"));
    }

    static Complexity analyze(String algorithm) {
        return db.get(algorithm.toLowerCase());
    }

    static void print(Complexity c) {
        System.out.println("\n=== " + c.algorithm() + " ===");
        System.out.println("  Best case:     " + c.best());
        System.out.println("  Worst case:    " + c.worst());
        System.out.println("  Average case:  " + c.average());
        System.out.println("  Space:         " + c.space());
        System.out.println("  Stable:        " + c.stable());
        System.out.println("  Worst trigger: " + c.worstTrigger());
        System.out.println("  Mitigation:    " + c.mitigation());
    }

    public static void main(String[] args) {
        // Print all profiles:
        String[] algos = {"quicksort","mergesort","bubblesort","binarysearch","hashmap","linearsearch"};
        for (String a : algos) print(analyze(a));

        // 5 tests:
        System.out.println("\n=== TESTS ===");
        Complexity qs = analyze("quicksort");
        System.out.println("1. quicksort worst=O(n²): " + "O(n²)".equals(qs.worst()));
        System.out.println("2. mergesort consistent: " + analyze("mergesort").best().equals(analyze("mergesort").worst()));
        System.out.println("3. bubblesort best=O(n): " + "O(n)".equals(analyze("bubblesort").best()));
        System.out.println("4. hashmap average=O(1): " + "O(1)".equals(analyze("hashmap").average()));
        System.out.println("5. binarysearch space=O(1): " + "O(1)".equals(analyze("binarysearch").space()));
        System.out.println("All 5 pass: " +
            ("O(n²)".equals(qs.worst()) &&
             analyze("mergesort").best().equals(analyze("mergesort").worst()) &&
             "O(n)".equals(analyze("bubblesort").best()) &&
             "O(1)".equals(analyze("hashmap").average()) &&
             "O(1)".equals(analyze("binarysearch").space())));
    }
}
